const app = express();
const server = require("http").createServer(app);

const cors = require("cors");

app.use(cors());

const PORT = process.env.PORT || 4000;

server.listen(PORT, () => console.log(`Server is running on port ${PORT}`));

const io = require("socket.io")(server, {
  cors: {
    origin: "*",
    methods: ["GET", "POST"],
  },
});

let availableClients = [];

app.get("/", (req, res) => {
  res.send(`Server is running.`);
});

app.post("/match", (req, res) => {
  // Select the first available client with matching tags
  const tags = req.body.tags;
  const client = availableClients.find(c => c.tags === tags);

  if (client) {
    // Remove the client from the list of available clients
    const index = availableClients.indexOf(client);
    if (index > -1) {
      availableClients.splice(index, 1);
    }

    // Create a new room and add both clients to it
    const roomId = generateRoomId();
    client.socket.join(roomId);
    req.socket.join(roomId);

    // Notify both clients that they have been matched and provide them with the room ID
    io.to(client.socket.id).emit(`matched`, roomId);
    io.to(req.socket.id).emit(`matched`, roomId);

    return res.status(200).json({ roomId });
  }

  return res.status(404).json({ message: `No match found for tags: ${tags}` });
});

io.on(`connection`, (socket) => {
  console.log(`connected: `, socket.id);

  socket.on(`setTags`, (tags) => {
    console.log(`Client with ${tags}`);

    availableClients.push({ socket, tags });
  });

  socket.on(`disconnect`, () => {
    console.log("disconnected: ", socket.id);

    // Remove the client from the list of available clients when they disconnect
    const index = availableClients.findIndex(c => c.socket.id === socket.id);
    if (index > -1) {
      availableClients.splice(index, 1);
    }

    socket.broadcast.emit(`callEnded`);
  });

